from emulate_util import *
from emulate_init import *

# get call detail
def get_call_detail(poco):
    log.warning('get call detail start')
    try:
        if check_and_click(poco(desc="切换日期")):
            if check_and_click(poco(desc="按月查询")):
                months = wait_and_get(poco("pageNew").child("android.view.View")[1].offspring("android.widget.ListView")[1].child("android.view.View"))
                month_len = len(months)
                check_and_click(poco(desc="切换日期"))
                for i in range(month_len):
                    try:
                        if not loop_click(poco, i):
                            loop_click(poco, i)
                    except Exception as e:
                        log.exception(e)
                log.warning('get call detail end')
                return True
    except Exception as e:
        log.exception(e)
    log.warning('get call detail error')
    return False

# loop click the date calendar
def loop_click(poco, i):
    log.warning('loop click start: ' + str(i))
    try:
        if wait_and_click(poco(desc="切换日期")):
            if wait_and_get(poco(desc="按月查询")):
                months = wait_and_get(poco("pageNew").child("android.view.View")[1].offspring("android.widget.ListView")[1].child("android.view.View"))
                check_and_click(months[i])
                while True:
                    month_flag = wait_and_get(poco(descMatches='.*月的通话详单如下.*'))
                    if month_flag:
                        log.info(month_flag.attr('desc'))
                        break
                    sleep(0.1)
                swipe_to_bottom(poco)
                log.warning('loop click end: ' + str(i))
                return True
    except Exception as e:
        log.exception(e)
    log.warning('loop click error: ' + str(i))
    return False

# swipe to bottom
def swipe_to_bottom(poco):
    while True:
        if check_and_click(poco(descMatches='.*加载更多.*')):
            pass
        elif check_and_click(poco("com.sinovatech.unicom.ui:id/custom_dialog_cancel_button")):
            pass
        elif not poco(desc="已加载全部").exists():
            poco.swipe([0.9, 0.9], [0.9, 0.1], duration=0.05)
            sleep(1)
        elif poco(desc="已加载全部").exists():
            # get_all_element_attr(poco("pageNew").child("android.view.View")[1].offspring("android.view.View"))
            while not poco(descMatches='.*月的通话详单如下.*').exists():
                poco.swipe([0.9, 0.25], [0.9, 0.9], duration=0.05)
                sleep(0.1)
            break
        else:
            sleep(0.1)

if __name__ == '__main__':
    from emulate_init import *

    device, poco = init_device()
    get_call_detail(poco)



